<?php
namespace Tests\Feature\Inventory; use App\Models\Inventory\{InventoryCategory,InventoryCondition,InventoryItem,InventoryLocation,InventoryMeasurementUnit}; use App\Models\User; use App\Services\Inventory\InventoryLedgerService; use Database\Seeders\{RolePermissionSeeder,InventoryPermissionSeeder,InventoryMasterSeeder}; use Illuminate\Foundation\Testing\RefreshDatabase; use Tests\TestCase;
class InventoryModuleTest extends TestCase{use RefreshDatabase; private User $user; protected function setUp():void{parent::setUp();$this->seed(RolePermissionSeeder::class);$this->seed(InventoryPermissionSeeder::class);$this->seed(InventoryMasterSeeder::class);$this->user=User::factory()->create();$this->user->assignRole('super-admin');}
 public function test_admin_can_create_inventory_item_and_list_it():void{$cat=InventoryCategory::first();$unit=InventoryMeasurementUnit::first();$this->actingAs($this->user)->post(route('inventory.items.store'),['code'=>'KRS-001','name'=>'Kursi Siswa','inventory_category_id'=>$cat->id,'inventory_measurement_unit_id'=>$unit->id,'tracking_type'=>'quantity','is_active'=>1])->assertRedirect();$this->assertDatabaseHas('inventory_items',['code'=>'KRS-001']);$this->actingAs($this->user)->get(route('inventory.items.index'))->assertOk()->assertSee('Kursi Siswa');}
 public function test_ledger_addition_transfer_condition_and_reduction_keep_balances_valid():void{$cat=InventoryCategory::first();$unit=InventoryMeasurementUnit::first();$item=InventoryItem::create(['code'=>'KRS-002','name'=>'Kursi Siswa','inventory_category_id'=>$cat->id,'inventory_measurement_unit_id'=>$unit->id,'tracking_type'=>'quantity']);$baik=InventoryCondition::where('code','BAIK')->first();$rusak=InventoryCondition::where('code','RUSAK_RINGAN')->first();$l1=InventoryLocation::where('code','RK1')->first();$l2=InventoryLocation::where('code','RK2')->first();$svc=app(InventoryLedgerService::class);$svc->post(['type'=>'opening','transaction_date'=>now()->toDateString(),'inventory_item_id'=>$item->id,'to_location_id'=>$l1->id,'to_condition_id'=>$baik->id,'quantity'=>20,'reason'=>'Saldo awal madrasah'],$this->user->id);$svc->post(['type'=>'transfer','transaction_date'=>now()->toDateString(),'inventory_item_id'=>$item->id,'from_location_id'=>$l1->id,'to_location_id'=>$l2->id,'from_condition_id'=>$baik->id,'quantity'=>10,'reason'=>'Penempatan kelas'],$this->user->id);$svc->post(['type'=>'condition_change','transaction_date'=>now()->toDateString(),'inventory_item_id'=>$item->id,'from_location_id'=>$l2->id,'from_condition_id'=>$baik->id,'to_condition_id'=>$rusak->id,'quantity'=>2,'reason'=>'Kaki kursi longgar'],$this->user->id);$this->assertDatabaseHas('inventory_balances',['inventory_item_id'=>$item->id,'inventory_location_id'=>$l1->id,'inventory_condition_id'=>$baik->id,'quantity'=>10]);$this->assertDatabaseHas('inventory_balances',['inventory_item_id'=>$item->id,'inventory_location_id'=>$l2->id,'inventory_condition_id'=>$rusak->id,'quantity'=>2]);}
 public function test_insufficient_balance_is_rejected():void{$this->expectException(\Illuminate\Validation\ValidationException::class);$item=InventoryItem::create(['code'=>'SAPU-1','name'=>'Sapu','inventory_category_id'=>InventoryCategory::first()->id,'inventory_measurement_unit_id'=>InventoryMeasurementUnit::first()->id]);app(InventoryLedgerService::class)->post(['type'=>'reduction','transaction_date'=>now()->toDateString(),'inventory_item_id'=>$item->id,'from_location_id'=>InventoryLocation::first()->id,'from_condition_id'=>InventoryCondition::first()->id,'quantity'=>1,'reason'=>'Uji saldo kurang'],$this->user->id);}
 public function test_report_export_returns_csv():void{$this->actingAs($this->user)->get(route('inventory.reports.export'))->assertOk()->assertHeader('content-type','text/csv; charset=UTF-8');}}
